function fmt(n) {
  return "\u20AC" + Math.round(n).toLocaleString("nl-NL");
}

function tvLabel(tv) {
  if (tv < 1) return Math.round(tv * 12) + " maanden";
  const jaren = Math.floor(tv);
  const maanden = Math.round((tv - jaren) * 12);
  if (maanden === 0) return jaren + " jaar";
  if (maanden === 12) return jaren + 1 + " jaar";
  return jaren + " jaar en " + maanden + " maanden";
}

