  const totaalWh = apparaten.reduce((s, a) => s + (a.watt || 0) * (a.uren || 0), 0);
  const totaalW = apparaten.reduce((s, a) => s + (a.watt || 0), 0);
  const piekActief = aanvinkLijst.filter(a => a.actief).reduce((s, a) => s + (a.watt || 0), 0);

  const aanbevolenIdx = PAKKETTEN.findIndex(p => piekActief <= p.grens);
  const aanbevolen = PAKKETTEN[aanbevolenIdx >= 0 ? aanbevolenIdx : PAKKETTEN.length - 1];

  const kwhPerDag = totaalWh / 1000;
  const dieselPerJaarPerVoertuig = kwhPerDag * dagen;
  const brandstofPerVoertuig = dieselPerJaarPerVoertuig * diesel;
  const genPerVoertuig = brandstofPerVoertuig + 350;
  const genTotaal = genPerVoertuig * voertuigen;
  const prijs = aanbevolen.prijs || 7500;
  const investering = prijs * voertuigen;
  const eia = investering * 0.40;
  const invNaEia = investering - eia;
  const tv = invNaEia / Math.max(genTotaal, 1);
  const besparing5j = (genTotaal * 5) - invNaEia;
  const tvClamped = Math.min(tv, 5);
  const balkPct = aanbevolen.prijs ? Math.round((1 - tvClamped / 5) * 95 + 5) : 30;

  function voegApparaatToe(naam = "", watt = "", uren = "") {
    apparaatTeller++;
    setApparaten(prev => [...prev, { id: "app-" + apparaatTeller, naam, watt: watt || "", uren: uren || "" }]);
  }

  function verwijderApparaat(id) {
    setApparaten(prev => prev.filter(a => a.id !== id));
  }

  function updateApparaat(id, veld, waarde) {
    setApparaten(prev => prev.map(a => a.id === id ? { ...a, [veld]: waarde } : a));
  }

